		hey[i]=hey[i-1]+((bool)(a[i]==1));
		he[i]=hey[i]-hec[i];
	}
	build(1,1,n*2+5);
	add(1,n+2,0);
	f[0]=0x7fffffff;
	ll k=a[1],mn=0;
	for(int i=1;i<=n;i++){
		if(k!=a[i]){
			mn=f[i-1];
		}
		int l=he[i]-m,r=he[i]+m;//l<=he[j]<=r 
		f[i]=min(mn+1,cha(1,l+n+2,r+n+2)+1);//符合条件的 he[j]中用房间数最少的 
		//cout<<'a'<<he[i]<<"    "<<mn<<' '<<cha(1,l+n+2,r+n+2)<<'\n';//
		add(1,he[i]+n+2,f[i]);
		if(k!=a[i]){
			k=a[i];
		}
		mn=min(mn,f[i]);
		//cout<<f[i]<<'\n';//
	}
	cout<<f[n];
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=1e5+5;
const ll mod=1e9+9;
ll n,a[N],b[N],he[N],f[N],c[N],h2[N];
void add(int k,int v){
	for(int i=k;i<=n+1;i+=i&-i){
		b[i]+=v;
		b[i]%=mod;
	}
}
ll cha(int k){
	ll res=0;
	for(int i=k;i>=1;i-=i&-i){
		res+=b[i];
		res%=mod;
	}
	return res;
}
int main(){
