		c[i]=he[i];
	}
	sort(c+1,c+2+n);
	for(int i=0;i<=n;i++){
		h2[i]=lower_bound(c+1,c+2+n,he[i])-c;
	}
	f[0]=1;
	add(h2[0],1);
	for(int i=1;i<=n;i++){
		if(he[i]<0)continue;
		ll o=cha(h2[i])%mod;
		f[i]=o;
		f[i]%=mod;
		add(h2[i],f[i]);
