#include<bits/stdc++.h>
using namespace std;
#define ll long long
ll n,a[1000002],q,cnt[1000002],res,kuai[1000002];
struct A{
	ll id,l,r,ans;
}b[1000002];
bool cmp(A B,A C){
	if(kuai[B.l]==kuai[C.l])return B.r<C.r;
	return kuai[B.l]<kuai[C.l];
}
bool cmp2(A B,A C){
	return B.id<C.id;
}
void add(ll p){
	if(cnt[a[p]]==0)res++;
	cnt[a[p]]++;
}
void del(ll p){
	if(cnt[a[p]]==1)res--;
	cnt[a[p]]--;
}
int main(){
	ios::sync_with_stdio(false);
	cin>>n;
	ll len=sqrt(n),p=1;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		kuai[i]=p;
		if(i%len==0){
			p++;
		}
	}
	cin>>q;
	for(int i=1;i<=q;i++){
		cin>>b[i].l>>b[i].r;
		b[i].id=i;
	}
	sort(b+1,b+1+q,cmp);
	ll L=b[1].l,R=b[1].r;
	for(int i=L;i<=R;i++){
		add(i);
	}
	b[1].ans=res;
	for(int i=2;i<=q;i++){
		while(L<b[i].l){
			del(L);
			L++;
		}
		while(L>b[i].l){
			L--;
			add(L);
		}
		while(R<b[i].r){
			R++;
			add(R);
		}
		while(R>b[i].r){
			del(R);
			R--;
		}
		b[i].ans=res;
	}
	sort(b+1,b+1+q,cmp2);
	for(int i=1;i<=q;i++){
		cout<<b[i].ans<<'\n';
	}
	return 0;
}
